"""
MKT Context Commentary — Deuteronomy chapters 30–31
Run: python3 scripts/zc-context-deuteronomy-30-31-fill.py

Source data used:
- data/interlinear/deuteronomy.json
- data/translation/draft/mediating/deuteronomy.json

Key decisions in this range:
- Ch 30 vv. 1-10: The restoration oracle is treated as a real future-tense prediction
  of what will happen after the exile-curses of chs 28-29 play out; it is not merely
  a conditional 'if-then' — the verbs in vv. 3-6 are indicative promises, not conditions
- V. 6 circumcision of the heart: identified as the seed of the 'new heart' promises in
  Jer 31:31-34 and Ezek 36:26-27; Paul's Rom 2:29 and 10:6-8 citations are noted in context
- V. 14 'the word is near you': the ANE background (no 'divine messenger' required to
  ascend/descend for the law) is the first-level meaning; the Pauline application to
  the gospel is noted as secondary trajectory, not read back into Moses
- Ch 31 Joshua/Yeshua: the name connection is noted in context of the LXX tradition but
  not treated as the primary meaning of ch 31's Joshua commissioning
- The pillar of cloud theophany (31:15) is treated in relation to the Exodus cloud
  tradition — it is the final appearance of the cloud in the Torah
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUT = {
  "30": {
    "1": "<p>'When all these things have happened to you — the blessings and the curses' — chapter 30 opens in a future-perfect frame. Moses is not speaking hypothetically about a conditional future; he is looking beyond the curses of chapters 28-29 as events that <em>will</em> happen and framing the restoration as what comes after. The 'taking to heart' (<em>wahăšēbōtā ʾel-lĕbābĕkā</em>) is a cognitive-emotional turn: the exile will produce the reflective repentance that the land-blessing could not. The Hebrew concept of <em>lēb</em> (heart) encompasses will, intellect, and emotion — it is the whole self reconsidering, not merely an emotional response.</p>",
    "2": "<p>'When you and your children return to the LORD your God and obey him with all your heart' — the Hebrew root <em>šûb</em> (return) is the covenantal term for repentance. It carries the spatial metaphor of a journey that reverses direction — the same word used for physical return from exile and for theological turning-back-to-YHWH. Deuteronomy uses <em>šûb</em> in both senses simultaneously: the physical exile-return and the covenantal re-engagement are not separable. 'With all your heart and with all your soul' echoes the Shema (6:5) and the covenant summary (10:12-13) — the return must encompass the same totality that the original commitment demanded.</p>",
    "3": "<p>'Then the LORD your God will restore your fortunes' — <em>wĕšāb Yhwh ʾĕlōhêkā ʾet-šĕbûtĕkā</em>. The phrase <em>šāb šĕbût</em> (restore fortunes) is a technical idiom in prophetic literature (Jer 29:14; 30:3,18; 31:23; 32:44; 33:7,11,26; Ezek 16:53; Hos 6:11; Amos 9:14; Zeph 3:20; Ps 126:1-4). The restoration is comprehensive — all the conditions that the exile overturned are to be overturned again: land, prosperity, covenant standing, community. The divine compassion (<em>riḥam</em>) is the theological engine of the restoration — not Israel's merit but YHWH's covenant <em>raḥămîm</em> (deep compassion, from the root for 'womb').</p>",
    "4": "<p>'Even if you are exiled to the farthest horizon, the LORD your God will gather you' — the 'farthest horizon' (<em>qĕṣēh haššāmāyim</em>, the ends of the heavens) is a merism for geographical totality: no matter how far the dispersion reaches, the divine gathering will exceed it. The phrase 'gather you from there' anticipates the prophetic images of the Second Exodus: Isaiah 43:5-6 ('I will bring your children from the east and gather you from the west; I will say to the north, Give them up!'), Jeremiah 31:8-10, and Ezekiel 37:21 (the dry bones gathering). Deuteronomy's restoration promise seeds the imagery that the later prophets develop.</p>",
    "5": "<p>'The LORD your God will bring you to the land your ancestors possessed' — the land-return promise reconnects with the ancestral covenant of Abraham, Isaac, and Jacob that underlies all of Deuteronomy (1:8; 4:1; 6:10-11; 9:5; 26:3). The expression 'more prosperous and numerous than your ancestors' (<em>wĕhēṭibĕkā wĕhirbĕkā mēʾăbōtêkā</em>) echoes the Abrahamic promise of blessing and multiplication (Gen 22:17). The restoration is not merely a return to the pre-exile state but a surpassing of the best prior condition — a new act of divine blessing exceeding even the patriarchal era.</p>",
    "6": "<p>'The LORD your God will circumcise your heart and the hearts of your descendants' — the circumcision-of-the-heart promise is the theological climax of chapter 30 and the seed of the new covenant theology. Circumcision was the covenant-entry rite (Gen 17); to circumcise the heart is to apply the same covenant-marking to the will and desires, not merely the body. Deuteronomy has already used this image metaphorically (10:16: 'Circumcise therefore the foreskin of your heart'); 30:6 makes YHWH the subject — he will do what Israel could not do for itself. Jeremiah 31:31-34 (YHWH writing the law on the heart) and Ezekiel 36:26-27 (YHWH giving a new heart and his Spirit) are the prophetic development of this promise. Paul's 'circumcision of the heart, in the Spirit' (Rom 2:29) and 'the circumcision of Christ' (Col 2:11) stand in direct continuity with Deut 30:6.</p>",
    "7": "<p>'The LORD your God will inflict all these curses on your enemies' — the covenant reversal is complete: the curses that fell on Israel for covenant violation (chs 28-29) are redirected toward Israel's persecutors after the restoration. The 'enemies' and those who 'hate and persecute you' include the nations who exploited Israel during the exile. This promise has Isaianic parallels: Isaiah 14:1-2 (foreigners will serve restored Israel), Isaiah 49:25-26 (YHWH will contend with those who contend with Israel). The reversal of curse-and-blessing is not vindictiveness but covenant justice — YHWH's commitment to his people overturns the temporary order of exile.</p>",
    "8": "<p>'You will again obey the LORD and follow all his commands' — the future obedience of v. 8 is grounded in the heart-circumcision of v. 6: the obedience will be possible because YHWH has transformed the capacity to obey. The relationship between internal transformation and external obedience is the same logic that Jeremiah's new covenant develops (Jer 31:33: 'I will put my law within them and write it on their hearts') and that Paul expounds as the Spirit producing the fruit of the law in those who walk by the Spirit (Rom 8:4; Gal 5:22-23). The law is not abolished in the new covenant; the capacity to keep it is supernaturally provided.</p>",
    "9": "<p>'The LORD your God will make you most prosperous in all the work of your hands' — the restoration prosperity formula parallels the original blessing conditions of chapters 6-7: grain, livestock, children, land. The 'delight' (<em>yāśûś</em>) of YHWH in Israel's welfare reverses the 'delight' in their destruction (28:63: YHWH will delight to ruin and destroy them). The same verb is used for the divine emotional response in both directions: exile is the withdrawal of divine pleasure; restoration is its return. The phrase 'as he delighted in your ancestors' grounds the restoration in the ancestral covenant loyalty rather than in Israel's improved performance.</p>",
    "10": "<p>'If you obey the LORD your God and keep his commands and decrees written in this Book of the Law' — the conditional clause here grounds the restoration promise in ongoing covenant relationship rather than making it purely unconditional. The 'Book of the Law' (<em>sēper hattôrāh</em>) is explicitly the text of Deuteronomy itself — Moses is writing a document that Israel is to keep beside the ark (31:26) as a covenant witness. The combination 'turn to him with all your heart and with all your soul' is the restoration equivalent of the Shema's love-command: the return is complete only when it is total.</p>",
    "11": "<p>'What I am commanding you today is not too difficult for you or beyond your reach' — the accessibility of the covenant is a crucial theological claim. It counters any notion that the law was designed to be impossible, either as a trap or as a test of heroic achievement. The 'too difficult' (<em>lōʾ niplēʾt</em>, not too wonderful/extraordinary) and 'beyond your reach' (<em>lōʾ rĕḥōqāh</em>, not far off) both address the psychological and practical accessibility of the command. In Second Temple and rabbinic tradition, the accessibility of Torah became a point of pride: the Torah was given to Israel, not to the angels, and it was designed for human life, not for impossible perfection.</p>",
    "12": "<p>'It is not up in heaven, so that you have to ask, Who will ascend to get it?' — the heaven-and-sea accessibility sayings use a rhetorical form found in ancient Near Eastern wisdom literature. The ascent-to-heaven motif describes tasks that are superhuman: Mesopotamian and Egyptian traditions spoke of divine knowledge brought from heaven by a divine intermediary. Moses explicitly denies that the covenant requires this: no heavenly mediator is needed to descend with the divine law, because it is already present in the written Torah. The 'ascending to heaven' phrase has a NT parallel in John 3:13 ('No one has ascended to heaven except he who descended') — a different register but the same spatial theology.</p>",
    "13": "<p>'Nor is it beyond the sea, so that you have to ask, Who will cross the sea to get it?' — the crossing-the-sea counterpart to heaven emphasizes horizontal inaccessibility. In the ANE, the sea represented the far boundary of the known world; things 'beyond the sea' were inaccessible in principle, not merely in practice. The double denial (neither in heaven nor beyond the sea) establishes the covenant's radical accessibility: it is not hidden in the cosmic extremes but placed within human reach by divine gift. The ocean/sea boundary also recalls Israel's own crossing — the Exodus through the Reed Sea and the anticipated Jordan crossing — making the saying resonant with their actual experience of impossible-boundary crossing.</p>",
    "14": "<p>'No, the word is very near you; it is in your mouth and in your heart so you may obey it' — the <em>dābār</em> (word) that is near is the covenant-command, specifically the written Torah. Its presence in the mouth (recitation, teaching, daily hearing) and heart (inward appropriation) reflects the Shema's pedagogy (6:6-9: the commands are to be on your heart, spoken to your children, talked about everywhere). Paul quotes this verse in Romans 10:6-8, applying it to the word of faith about Christ: 'the word is near you, in your mouth and in your heart (that is, the word of faith that we proclaim).' Paul's application does not misread Moses; it traces the trajectory of divine accessibility from the written Torah through the incarnate Word to the proclaimed gospel.</p>",
    "15": "<p>'See, I set before you today life and prosperity, death and destruction' — the two-ways structure is a covenant-document genre element. Hittite suzerainty treaties typically concluded with a blessings-and-curses section listing the consequences of covenant loyalty and violation. Deuteronomy has already given the full blessing-and-curse lists (chs 27-28); chapter 30 is the culminating summary: the choice is life or death. The 'setting before' (<em>nātattî lĕpānêkā</em>) is a legal-judicial gesture — the covenant terms are formally presented as the occasion for a binding decision. This verse and v. 19 form the rhetorical frame of the chapter's two-ways conclusion.</p>",
    "16": "<p>'For I command you today to love the LORD your God, to walk in his ways, and to keep his commands, decrees, and laws' — the covenant summary formula appears here in its most compressed form (cf. 6:4-5; 10:12-13; 11:1,13,22; 19:9). The triad 'love — walk — keep' represents the totality of covenant commitment: <em>ʾāhab</em> (relational loyalty), <em>hālak bĕdĕrākāyw</em> (practical life ordering), and <em>šāmar miṣwōtāyw</em> (specific obedience. The promise attached — 'then you will live and increase' — is the covenant blessing in its most basic form: the land, life, and growth that YHWH gives when the covenant is honored.</p>",
    "17": "<p>'But if your heart turns away and you refuse to listen, and if you are drawn away to bow down to other gods' — the covenant-violation scenario uses the same three-stage apostasy pattern seen throughout Deuteronomy: internal turn (heart-turning away from YHWH), external refusal (refusing to hear the covenant word), and cultic action (bowing to other gods). 'Drawn away' (<em>niddaḥtā</em>, passive: to be thrust aside, led astray) acknowledges that the apostasy has an external seductive element — other gods are attractive and the surrounding cultures have pull. The individual and social dimensions of covenant disloyalty are both present.</p>",
    "18": "<p>'I declare to you this day that you will certainly be destroyed' — the prophetic certainty formula 'I declare to you this day' (<em>higgadtî lākem hayyôm</em>) makes this a formal covenant warning, not a general observation. 'Certainly destroyed' (<em>ʾābōd tōʾbēdûn</em>, infinitive absolute + finite verb for emphasis) is the same construction used for the doomed Canaanite cities in 12:2 — destruction that is thorough, not partial. 'You will not live long in the land' connects to the land-tenure condition established throughout Deuteronomy: covenant fidelity is the lease condition for the land.</p>",
    "19": "<p>'This day I call the heavens and the earth as witnesses against you' — the cosmic witness formula (<em>hāʿîdōtî bākem hayyôm ʾet-haššāmayim wĕʾet-hāʾāreṣ</em>) is the closing act of a formal covenant ceremony. In ANE suzerainty treaties, the gods of both parties served as treaty witnesses; Israel's monotheism replaced the divine witnesses with the permanent, morally reliable heavens-and-earth (cf. 4:26; 31:28; 32:1; Isa 1:2; Mic 6:1-2). The cosmos itself is called to observe and eventually to report on Israel's covenant behavior. 'Choose life' (<em>ûbāḥartā baḥayyîm</em>) is a formal invitation rather than a command — the covenant allows choice while strongly urging the right one.</p>",
    "20": "<p>'By loving the LORD your God, listening to his voice, and holding fast to him. For the LORD is your life' — the chapter ends with a triad that mirrors the opening command (v. 16): love, listening, and clinging (<em>dābaq</em>, holding fast — the same word used for Ruth holding fast to Naomi: Ruth 1:14; and for the husband-wife bond: Gen 2:24). 'The LORD is your life' (<em>kî hûʾ ḥayyêkā</em>) is an extraordinary theological compression: YHWH is not merely the source of life or the condition for life — he <em>is</em> life, in the same way that John will say 'in him was life' (John 1:4). The land, prosperity, and long years are the visible expressions of that foundational life-in-YHWH.</p>",
  },
  "31": {
    "1": "<p>'Moses went and spoke these words to all Israel' — the chapter transition marks the formal beginning of Moses's farewell address, the final public speech of his life. The phrase 'all Israel' (<em>kol-yiśrāʾēl</em>) signals a formal assembly setting — the same audience formula used for the covenant renewal ceremony of chapter 29 (v. 2). Moses now speaks not as lawgiver but as the covenant mediator completing his term of office. The 'speaking' (<em>waydabbēr</em>) that has governed all of Deuteronomy since 1:1 is here contextualized as farewell: everything previously spoken is now the legacy being formally handed off.</p>",
    "2": "<p>'I am a hundred and twenty years old today. I am no longer able to lead you out and bring you in' — Moses's age (120 years) divides neatly into three equal periods of forty years: forty in Egypt (Acts 7:23: 'when he was forty years old'), forty in Midian (Exod 7:7: when he appears before Pharaoh he is eighty), and forty in the wilderness (Deut 8:2). The literary shaping of his life around three forty-year periods reflects the same wilderness-generation number — the covenant generation's life and Moses's life are co-extensive. 'I am no longer able to lead you out and bring you in' is an administrative formula for military leadership — the same idiom used for Joshua taking command (Josh 14:11) and for the role of a king (1 Sam 18:16).</p>",
    "3": "<p>'The LORD your God himself will cross over before you' — the divine advance-crossing is the theological claim that resolves the problem of Moses's incapacitation: it does not matter that Moses cannot cross, because YHWH himself leads the invasion. 'Cross over before you' (<em>ʿōbēr lĕpānêkā</em>) recalls the pillar of cloud leading the Exodus (Exod 13:21) and YHWH's angel going before Israel (Exod 23:20,23; 33:2). Joshua is named as the human executor, but YHWH is the primary agent: 'The LORD has said' — Joshua's leadership is authorized by, and secondary to, the divine mandate.</p>",
    "4": "<p>'The LORD will deal with them just as he dealt with Sihon and Og' — the Sihon-and-Og citation (cf. 2:24-3:11) functions as the paradigmatic precedent for Cisjordanian conquest. Throughout the conquest narrative (Josh 2-12), Rahab's confession shows that Canaanite awareness of the Sihon-Og precedent has already broken their military morale: 'We heard how the LORD dried up the water of the Red Sea ... and what he did to Sihon and Og' (Josh 2:10). The two Transjordanian kings serve as the proof-of-concept for every subsequent battle — if YHWH gave them, he will give the others.</p>",
    "5": "<p>'The LORD will hand them over to you, and you must deal with them according to all the commands I have given you' — the handing-over (<em>nātan</em>, give) and the commanded action creates a two-part structure that runs through all conquest narratives: YHWH's gift of the enemy + Israel's obedient response. The 'commands I have given you' regarding the Canaanite nations (the herem, complete destruction: 7:1-5; 20:16-18) are the referent — the conquest is not military opportunism but covenant action with specific terms of engagement.</p>",
    "6": "<p>'Be strong and courageous. Do not be afraid or terrified by them — the LORD your God goes with you' — the courage formula appears seven times in Joshua 1 (Josh 1:6,7,9,18) as Joshua's commissioning refrain. Its origin here, on Moses's lips to the entire assembled people, establishes it as the foundational courage-theology of the conquest. The theological basis is not military confidence or numerical advantage but the divine presence: 'the LORD your God goes with you.' The 'he will never leave you or abandon you' (<em>lōʾ yarpĕkā wĕlōʾ yaʿazbĕkkā</em>) echoes the covenant-loyalty formula and becomes the direct content of YHWH's own assurance to Joshua in v. 8. Hebrews 13:5 quotes this promise as grounding Christian contentment: 'I will never leave you nor forsake you.'</p>",
    "7": "<p>'Moses summoned Joshua and said to him before all Israel, Be strong and courageous' — the public commissioning of Joshua is a formal ceremony of leadership transition. 'Before all Israel' is the witness-community of the covenant assembly; the commissioning must be public to establish Joshua's legitimate authority over the entire people. The formula 'you will be the one who takes them in to possess it' (<em>ʾattāh tābōʾ ʾet-hāʾāreṣ</em>) is the fulfillment language — Joshua's role is defined by the promise to the ancestors that has not yet been realized. He is the executor of the ancestral covenant's land-clause.</p>",
    "8": "<p>'The LORD himself goes before you. He will be with you; he will never leave you or abandon you' — this verse repeats v. 6's assurance but now applies it specifically to Joshua, not to the whole people. The shift from 'us' (v. 6: 'Do not be afraid or terrified') to direct address of Joshua makes the assurance personal and covenantal. Joshua is receiving what Moses received at the burning bush: the presence-promise that grounds leadership. The 'do not be afraid or discouraged' (<em>lōʾ tîrāʾ wĕlōʾ tēḥāt</em>) covers both external danger and internal psychological wavering — the completeness of the divine support leaves no category of fear unaddressed.</p>",
    "9": "<p>'Moses wrote down this law and handed it over to the Levitical priests who carried the ark of the covenant' — the writing of the Torah is a formal act of covenant documentation. In ANE suzerainty treaties, the written treaty document was deposited in the sanctuary of both parties and was to be read publicly at regular intervals. Deuteronomy follows this pattern precisely: the Torah is written (this verse), deposited beside the ark (v. 26), and commanded to be read every seven years (v. 10-11). The Levitical priests (ark-carriers) and elders together receive the document, establishing dual custodianship — priestly (ritual) and civic (elders) responsibility for the covenant text.</p>",
    "10": "<p>'At the end of every seven years, during the Festival of Booths in the year of debt cancellation' — the seven-year Torah reading is coordinated with the Shemitah (sabbatical year) and the Festival of Sukkot (Booths). The debt-cancellation year (shemitah, ch. 15) reset economic inequality; the Sukkot reading reset covenant knowledge. Sukkot was the most attended festival in the Jewish calendar — all pilgrims gathered in Jerusalem for eight days. The sabbatical-year timing ensured a maximum seven-year gap between public covenant-readings, with the next reading immediately after the economic reset. The combination of economic and covenantal renewal in the same year is not coincidental.</p>",
    "11": "<p>'When all Israel comes to appear before the LORD your God at the place he chooses, you must read this law aloud before all Israel in their hearing' — the public Torah reading (Hebrew: <em>haqhēl</em> ceremony, from the root for assembly/congregation) was a mass covenant-renewal ceremony. The second-century BCE practice of public Torah reading in synagogues and the annual lectionary cycle ultimately derive from this institution. Nehemiah 8 depicts the post-exilic restoration of the Shemitah-year reading under Ezra — a deliberate reconnection with this specific Deuteronomic ordinance after the long exile-suspension.</p>",
    "12": "<p>'Gather the entire people — men, women, children, and the foreigners living in your towns' — the comprehensiveness of the assembly (men, women, children, foreigners) is theologically significant. The covenant reading is not a men-only legal gathering; it is a total-community hearing. Children who cannot yet comprehend the legal content and foreigners who are not ethnic Israelites are nonetheless present — the covenant knowledge is to be shared across every demographic boundary within the town. 'So they can hear, learn to fear the LORD, and carefully follow all the words' — hearing → fear → obedience is the covenant pedagogy sequence that Deuteronomy consistently models.</p>",
    "13": "<p>'The children who do not yet know the law must hear it and learn to fear the LORD your God throughout all the time you live in the land' — the generational transmission of covenant knowledge is explicitly the purpose of the children's presence. They cannot yet fully understand, but they hear; understanding will come as they mature. This reflects a model of religious formation through immersive participation before cognitive comprehension — the child's presence at the assembly creates a formative experience that precedes doctrinal understanding. The Passover Seder's pedagogical structure (the child asking 'Why do we do this?': Exod 12:26-27) reflects the same principle.</p>",
    "14": "<p>'The LORD said to Moses, The time of your death is drawing near. Call Joshua and come to the tent of meeting so I can commission him' — the divine summons to the tent of meeting is the final formal audience of Moses's life. The tent of meeting (<em>ʾōhel môʿēd</em>) was the sanctuary for direct divine-human encounter (Exod 33:7-11: YHWH would speak with Moses 'face to face, as a man speaks with his friend'). This final meeting commissions Moses's successor in the same sacred space where the covenant was mediated throughout the wilderness period. The parallel to Joshua 1, where YHWH directly addresses Joshua at the Jordan crossing, completes the transition of prophetic authority.</p>",
    "15": "<p>'The LORD appeared at the tent in a pillar of cloud, which stood at the entrance of the tent' — the pillar of cloud is the visible form of the divine presence that has accompanied Israel since the Exodus (Exod 13:21-22; 14:19,24; 40:34-38). Its appearance at the tent entrance for Joshua's commissioning is the last appearance of the cloud-pillar in the Torah; it will not be mentioned again until the cloud fills Solomon's temple (1 Kings 8:10-11). The cloud standing at the entrance (rather than descending or entering the tent) may mark a threshold moment — YHWH is present but the era of direct tent-meeting is closing as the conquest era begins.</p>",
    "16": "<p>'After that, this people will rise up and chase after the foreign gods of the land they are entering' — the divine prophecy of Israel's future apostasy is remarkable: YHWH knows and states in advance that the conquest will be followed by Canaanite-cult syncretism. This is not a conditional warning ('if you disobey') but a prophetic certainty ('you will'). The covenantal rationale for giving this prophecy is that it becomes the content of the song-witness (vv. 19-22) — a text that will testify against Israel when the predicted apostasy occurs. The foreknowledge does not excuse the sin; it ensures that the sin cannot later be reframed as an understandable mistake. The Judges cycle of apostasy-judgment-rescue-apostasy is the historical outworking of this prediction.</p>",
    "17": "<p>'My anger will blaze against them that day, and I will abandon them and hide my face from them' — the hiding of the divine face (<em>wĕhissartî pānay mēhem</em>) is the most severe expression of covenantal withdrawal. Throughout the psalms, God-forsakenness is the extremity of suffering (Ps 22:1: 'My God, my God, why have you forsaken me?'). The hiddenness is not permanent (v. 18 qualifies it as an act of judgment for specific sin) but it creates the condition of total vulnerability: without divine protection, 'many disasters and troubles will overwhelm them.' Israel asking 'Have all these evils come upon us because our God is no longer with us?' is the correct diagnosis of their situation — they will understand the mechanism even as they experience the consequence.</p>",
    "18": "<p>'I will certainly conceal my face that day because of all the evil they have done — they have turned to other gods' — the double certainty ('certainly conceal': <em>wĕʾānōkî hastēr ʾastîr</em>, infinitive absolute + finite verb) mirrors the double certainty of the covenant curses. The construction is the same as used for Israel's expected exile: emphatic certainty, not conditionality. The divine hiddenness is directly proportional to Israel's act of turning (<em>pānāh</em>, they have turned their face) to other gods — the divine face-hiding mirrors the human face-turning. The theological symmetry is stark: you turn away from me; I turn away from you.</p>",
    "19": "<p>'Write down this song and teach it to the Israelites. Put it in their mouths, so that this song will serve as a witness' — the Song of Moses (chapter 32) is a covenant-witness document in the tradition of ANE treaty documents. Written covenant texts in the ANE served as legal witnesses: they recorded the terms and would 'testify' against a party who violated them. The Song is internalized differently from the written Torah: rather than being written and deposited (as the Torah text: v. 26), it is placed in the mouths of the people — it becomes oral tradition, embedded in communal memory, harder to lose than a written scroll. This is the covenant-witness that cannot be destroyed even if the text is lost.</p>",
    "20": "<p>'When I bring them into the land of milk and honey, and they eat until they are full and become prosperous, they will turn to other gods' — the prosperity-apostasy prediction echoes the pattern already identified in 8:10-14 (eat-full-forget-pride) and 32:15 (Jeshurun grew fat and kicked). The 'land of milk and honey' formula appears throughout Deuteronomy (6:3; 11:9; 26:9,15; 27:3) as the standard description of the land's agricultural bounty. The prediction that the land's abundance itself becomes the occasion for apostasy is the irony at the heart of the covenant: the blessing designed to deepen loyalty actually weakens it when the blessing is detached from the Blesser.</p>",
    "21": "<p>'When disasters and troubles overwhelm them, this song will testify against them' — the song's legal function as witness (<em>ʿēd</em>, legal witness) is foregrounded. In the covenant-lawsuit genre (Hebrew <em>rîb</em>), the plaintiff (YHWH) would bring charges against the defendant (Israel) before a court; the witnesses (heaven, earth, the song) would testify. The prophetic lawsuit literature (Isa 1:2-4; Jer 2:4-13; Mic 6:1-8) is exactly this form: YHWH summoning the cosmic court and presenting evidence of Israel's covenant violation. The song's being in the people's mouths means the testimony is irrefutable — they have preserved their own indictment.</p>",
    "22": "<p>'Moses wrote down this song that very day and taught it to the Israelites' — the immediate execution of the divine command (write → teach) compresses the transmission chain: Moses does not merely write and deposit but personally teaches it, making him the first teacher of his own indictment. The song (ch. 32) is therefore simultaneously a Torah composition of Moses (written) and an oral tradition he inaugurated (taught). The written-and-oral duality of Torah transmission — text as deposit and recitation as living practice — is established in this single verse. Deuteronomy will also later be called both 'this book' and 'these words' to reflect the same dual mode.</p>",
    "23": "<p>'The LORD then commissioned Joshua son of Nun, saying, Be strong and courageous' — v. 23 distinguishes between Moses commissioning Joshua before the people (v. 7) and YHWH directly commissioning Joshua at the tent. The divine direct-commission creates Joshua's prophetic authority — he is not merely Moses's designated successor but YHWH's directly appointed leader. 'I will be with you' (<em>kî ʾānōkî ʾehyeh ʿimmāk</em>) is the formula that YHWH used with Moses at the burning bush (Exod 3:12: 'I will be with you') — the continuity of the divine-presence-with-the-leader is the thread of covenant leadership through Moses to Joshua. Joshua 1:5,9 develops this commission at length.</p>",
    "24": "<p>'When Moses had finished writing out the entire law in a book' — the completion formula marks the close of the Mosaic legislative corpus. 'The entire law' (<em>ʾet-dibrê hattôrāh-hazzōʾt</em>) refers to Deuteronomy specifically, not the entire Pentateuch — Moses is completing the covenant document he began dictating in chapter 1. The 'book' (<em>sēper</em>) is a scroll; the same word is used for the book of the covenant in Exodus 24:7 (Moses reads the covenant to Israel and the people accept it). The writing and the reading are both legally significant acts — the covenant text's authority is established by its written form.</p>",
    "25": "<p>'Moses gave a command to the Levites who carried the ark of the covenant of the LORD' — the depositional command goes to the ark-carrying Levites rather than to the Aaronide priests. In 10:8, 'the tribe of Levi' was designated to carry the ark; in 31:9, the same Levitical priests received the written Torah from Moses. The ark-and-Torah together formed the covenant archive: the tablets of the Ten Commandments inside the ark (10:5) and the book of Deuteronomy beside it (v. 26). The two-layer archive reflects the two-layer covenant structure: the foundational words (Ten Commandments) and the elaborated covenant law (Deuteronomy).</p>",
    "26": "<p>'Take this scroll of the law and place it beside the ark of the covenant of the LORD your God. It will remain there as a witness against you' — the law placed beside the ark parallels the ANE treaty deposit. Hittite suzerainty treaties were deposited in the sanctuaries of both parties; the treaty was to be read periodically before the divine witness. Israel's single sanctuary placed both the foundational covenant (tablets inside the ark: Deut 10:2,5) and the elaborated covenant-law (Deuteronomy beside the ark) in the same sacred deposit. The 'witness against you' function means the scroll will eventually be brought out to testify in the covenant-lawsuit when Israel violates its terms — exactly what happens in 2 Kings 22:8-13 when Hilkiah finds the book of the law in the temple and Josiah tears his garments.</p>",
    "27": "<p>'I know how rebellious and stubborn you are. Even today, while I am still with you, you have been defiant' — Moses's candid assessment of Israel's character is grounded in the wilderness record: even during the forty years of divine provision, Israel complained repeatedly (Exod 16-17; Num 11; 14; 16; 20; 21). The 'even today' is the most damning element — present-tense rebellion in Moses's presence, not merely future-tense predicted rebellion. The progression ('How much worse will it be after I am gone?') uses the standard <em>qal wahomer</em> argument form: if the lesser is true, the greater certainly is. It is the same logic the prophets use in arguing from Israel's checkered history to their predicted future failure.</p>",
    "28": "<p>'Gather all the elders of your tribes and your officials so I can speak these words in their hearing and call heaven and earth to testify against them' — the assembly of elders-and-officials parallels the covenant-assembly formula throughout Deuteronomy (1:13-15; 5:23; 27:1; 29:10). The heaven-and-earth witness invocation (also at 4:26; 30:19; 32:1) closes the legal preparation for the Song: Moses is formally constituting the covenant-court before reciting the witness-song. Prophetic lawsuits (Isaiah 1:2: 'Hear, O heavens, and listen, O earth') draw directly on this Deuteronomic witness formula.</p>",
    "29": "<p>'I know that after my death you will become deeply corrupt and turn away from everything I have commanded' — Moses's death-prophecy of Israel's apostasy is the most unambiguous statement in all of Torah that the covenant will be violated. 'After my death' (<em>ʾaḥărê môtî</em>) sets the timeline: the leader who has kept Israel intermittently on course for forty years will be gone, and the centrifugal forces of Canaanite culture will prove too strong for the unled community. 'What your hands make' — the idol-making of Exodus 32 (the golden calf made while Moses was on the mountain) is the paradigm; the predicted apostasy is a return to the type already established. Deuteronomy's honest pessimism about Israel's covenant faithfulness is the theological backdrop for every prophetic indictment from Amos through Malachi.</p>",
    "30": "<p>'Moses then recited the words of this song in the hearing of the entire assembly of Israel, from beginning to end' — the chapter closes with the public recitation that v. 22 prepared. The Song of Moses (ch. 32) is not merely a written deposit but a performed act: Moses himself delivers it to the full assembly. The phrase 'from beginning to end' (<em>lĕtumām</em>, to their completion) ensures the complete transmission — no verse is skipped, no section summarized. The oral performance by the author before the entire community is the founding act of the Song's transmission as both oral tradition and written text, establishing a dual-mode preservation parallel to v. 19's 'put it in their mouths.'</p>",
  },
}

def main():
    existing = load_comm('mkt-context', 'deuteronomy')
    merge_comm(existing, DEUT)
    save_comm('mkt-context', 'deuteronomy', existing)
    il = json.loads((ROOT / 'data/interlinear/deuteronomy.json').read_text())
    out = json.loads((ROOT / 'data/commentary/mkt-context/deuteronomy.json').read_text())
    all_ok = True
    for ch in range(30, 32):
        ck = str(ch)
        missing = [v for v in il.get(ck, {}) if v not in out.get(ck, {})]
        if missing:
            print(f'  ch {ch} MISSING: {missing}')
            all_ok = False
        else:
            print(f'  ch {ch}: OK ({len(il.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present ✓')

if __name__ == '__main__':
    main()
